-- Exemple 3 : Modele Sequential (Mini-MLP pour MNIST)
-- ===========================================================

-- Type pour representer un module
-- Note : `deriving Repr` est necessaire pour reutiliser `Module` dans
-- d'autres structures derivant `Repr` (ex. `ExportableModel` plus loin).
-- Lean genere automatiquement l'instance recursive `Repr Module` ET
-- `Repr (List Module)` grace au cas `sequential`.
inductive Module where
  | linear : LinearLayer → Module
  | relu : Module
  | sequential : List Module → Module
  deriving Repr

-- Exemple : Mini-MLP 784 -> 128 -> 10
def miniMLP : Module :=
  Module.sequential [
    Module.linear (
      { inFeatures := 784
        outFeatures := 128
        weight := { shape := [128, 784], data := [] }
        bias := { shape := [128], data := [] }
      }
    ),
    Module.relu,
    Module.linear (
      { inFeatures := 128
        outFeatures := 10
        weight := { shape := [10, 128], data := [] }
        bias := { shape := [10], data := [] }
      }
    )
  ]

#eval "Mini-MLP defined with 3 layers"

-- Exercice 1 : propagation IBP à travers une couche à poids négatif puis ReLU.
-- Réutilise `Interval` et `reluIBP` définis plus haut (section 5, IBP).
-- Seul `linearIBP` est (re)défini ici (il n'apparaît que dans l'exemple guidé 1).
def linearIBP (i : Interval) (w : Float) (b : Float) : Interval :=
  if w ≥ 0 then
    { lower := i.lower * w + b, upper := i.upper * w + b }
  else
    { lower := i.upper * w + b, upper := i.lower * w + b }

-- TODO étudiant : calculez la borne après Linear(w = -3.0, b = 1.0) puis ReLU.
def exo1_input  : Interval := { lower := -1.0, upper := 2.0 }
def exo1_layer  : Interval := { lower := 0.0, upper := 0.0 }  -- TODO étudiant : linearIBP exo1_input (-3.0) 1.0
def exo1_output : Interval := reluIBP exo1_layer

