from itertools import product

def sensitivity_of_function(f, n):
    """Calcule la sensibilite s(f) d'une fonction booleenne sur n bits."""
    max_s = 0
    for x in product([0, 1], repeat=n):
        fx = f(*x)
        local_s = 0
        for i in range(n):
            x_flip = list(x)
            x_flip[i] = 1 - x_flip[i]
            if f(*x_flip) != fx:
                local_s += 1
        max_s = max(max_s, local_s)
    return max_s

# Fonctions booleennes classiques
def f_and(*args): return int(all(args))
def f_or(*args): return int(any(args))
def f_xor(*args): return sum(args) % 2
def f_majority(*args): return int(sum(args) > len(args) / 2)

functions = {
    'AND': f_and,
    'OR': f_or,
    'XOR (parite)': f_xor,
    'MAJORITY': f_majority,
}

print(f"{'Fonction':<18} | {'s(f) sur 3 bits':<15} | {'s(f) sur 4 bits':<15}")
print("-" * 55)
for name, f in functions.items():
    s3 = sensitivity_of_function(f, 3)
    s4 = sensitivity_of_function(f, 4)
    print(f"{name:<18} | {s3:<15} | {s4:<15}")

from itertools import product
import random
import numpy as np

def sensitivity_of_function(f, n):
    max_s = 0
    for x in product([0, 1], repeat=n):
        fx = f(*x)
        local_s = 0
        for i in range(n):
            x_flip = list(x)
            x_flip[i] = 1 - x_flip[i]
            if f(*x_flip) != fx:
                local_s += 1
        max_s = max(max_s, local_s)
    return max_s

import random
from itertools import product as iter_product

def compute_degree(f_values, n):
    """Calcule le degre polynomial d'une fonction booleenne f : {0,1}^n -> R.
    Utilise la transformee de Moebius (inclusion-exclusion)."""
    table = {}
    for i, x in enumerate(iter_product([0, 1], repeat=n)):
        table[x] = f_values[i]
    coeffs = {}
    for S in range(1 << n):
        val = 0
        for T in range(S + 1):
            if (T & S) == T:
                x_T = tuple((T >> i) & 1 for i in range(n))
                sign = (-1) ** (bin(S ^ T).count('1'))
                val += sign * table[x_T]
        coeffs[S] = val
    max_deg = 0
    for S, c in coeffs.items():
        if abs(c) > 1e-10:
            max_deg = max(max_deg, bin(S).count('1'))
    return max_deg

def random_boolean_function_values(n):
    return [random.randint(0, 1) for _ in range(1 << n)]

# Monte Carlo sur Q4
n = 4
num_samples = 500
random.seed(42)

min_ratio = float('inf')
violations = 0
s_deg_pairs = []

for _ in range(num_samples):
    f_vals = random_boolean_function_values(n)
    def make_f(fv):
        def f(*args):
            idx = sum(a << i for i, a in enumerate(args))
            return fv[idx]
        return f
    f = make_f(f_vals)
    s = sensitivity_of_function(f, n)
    deg = compute_degree(f_vals, n)
    sqrt_deg = deg ** 0.5 if deg > 0 else 0
    s_deg_pairs.append((s, sqrt_deg, deg))
    if sqrt_deg > 0:
        min_ratio = min(min_ratio, s / sqrt_deg)
    if s < sqrt_deg - 1e-10:
        violations += 1

print(f"Monte Carlo sur Q4 : {num_samples} fonctions booleennes aleatoires")
print(f"Violation de s(f) >= sqrt(deg(f)) : {violations}/{num_samples}")
print(f"Ratio minimum s(f)/sqrt(deg(f)) observe : {min_ratio:.3f}")
print(f"\nEchantillon (tries par degre) :")
for s_val, sq_val, d_val in sorted(s_deg_pairs, key=lambda x: x[2])[:8]:
    if sq_val > 0:
        print(f"  s(f)={s_val}, sqrt(deg)={sq_val:.2f}, deg={d_val}, ratio={s_val/sq_val:.2f}")
    else:
        print(f"  s(f)={s_val}, deg={d_val} (constante)")

# Helpers de lecture single-source-of-truth des .lean (lecture directe du depot)
DECL_RE = re.compile(r"^\s*(theorem|lemma|def|abbrev|instance)\s+([\w'À-ſ]+)")

def count_real_sorry(text: str) -> int:
    """Compte les vrais `sorry` tactiques en excluant commentaires de ligne et blocs /- -/."""
    n, in_block = 0, False
    for line in text.splitlines():
        s = line.strip()
        if in_block:
            if '-/' in s:
                in_block = False
            continue
        if s.startswith('/-'):
            if '-/' not in s:
                in_block = True
            continue
        code_part = s.split('--', 1)[0]
        if re.search(r'\bsorry\b', code_part):
            n += 1
    return n

def show_lean(relpath: str, max_lines: int = 0):
    """Affiche les declarations (theorem/def/...) d'un fichier .lean reel + comptage sorry."""
    f = WIN_LEAN_PROJECT / relpath
    text = f.read_text(encoding='utf-8')
    decls = [(i + 1, m.group(1), m.group(2))
             for i, l in enumerate(text.splitlines())
             for m in [DECL_RE.match(l)] if m]
    sorry = count_real_sorry(text)
    print(f"=== {relpath}  ({len(text.splitlines())} lignes, sorry reels = {sorry}) ===")
    for ln, kind, name in decls:
        print(f"  L{ln:>4}  {kind:<8} {name}")
    if max_lines:
        print("-" * 60)
        for l in text.splitlines()[:max_lines]:
            print(l)
    return sorry

## 3. La règle B3/S23

Pour chaque cellule, on compte ses voisins vivants :
- **Birth (B3)** : une cellule **morte** avec exactement 3 voisins vivants naît ;
- **Survival (S23)** : une cellule **vivante** avec 2 ou 3 voisins vivants survit ;
- sinon la cellule est morte à la génération suivante.

## 1. FRACTRAN en une phrase

Un programme FRACTRAN est une **liste de fractions positives**. Étant donné un entier $N$ :
1. on cherche la **première** fraction $\frac{a}{b}$ telle que $N \cdot \frac{a}{b}$ soit entier (i.e. $b \mid N \cdot a$) ;
2. on remplace $N$ par $N \cdot \frac{a}{b}$ ;
3. on recommence. Si aucune fraction ne s'applique, la machine s'arrête.

C'est tout. Conway a montré que ce modèle trivial est **Turing-complet** : il peut calculer tout ce qu'un ordinateur peut calculer.

## 7. Pourquoi FRACTRAN est universel

Le résultat de Conway (Turing-complétude) dépasse le cadre de ce notebook — il repose sur un encodage des registres et instructions d'une machine à compteurs comme facteurs premiers d'un grand entier $N$. L'intuition :

- chaque **variable** $v_i$ est codée par l'exposant d'un nombre premier $p_i$ dans la factorisation de $N$ ;
- **incrémenter** $v_i$ = multiplier $N$ par $p_i$ ; **décrémenter** = diviser ;
- une **instruction conditionnelle** « si $v_i > 0$ alors $A$ sinon $B$ » = une fraction qui ne s'applique que si $p_i$ divise $N$.

Avec ce codage, n'importe quel programme se traduit en une liste de fractions. Le programme générateur de premiers ci-dessus en est l'illustration la plus célèbre. La **preuve formelle** de la Turing-complétude (et la correction du `primeProgram` spécifique) vivent dans le module `Conway.Fractran` du dépôt ; ce notebook en donne l'**expérience calculatoire** en REPL.

